```typescript
interface Address {
  id: string;
  name: string;
  street: string;
  city: string;
  postalCode: string;
  country: string;
  isDefault: boolean;
}

const useAddressStore = create((set) => ({
  addresses: [],
  setAddresses: (addresses) => set({ addresses }),
  addAddress: (address) => set((state) => ({ addresses: [...state.addresses, address] })),
  updateAddress: (id, updated) => set((state) => ({
    addresses: state.addresses.map(addr => addr.id === id ? { ...addr, ...updated } : addr)
  })),
  deleteAddress: (id) => set((state) => ({
    addresses: state.addresses.filter(addr => addr.id !== id)
  }))
}));
```

